  expect(response.statusCode).toBe(400)
  const body = response.json()
  expect(body.status).toBe(400)
})

test('X-Request-ID: valid UUID v4 is echoed back', async () => {
  const validUUID = '550e8400-e29b-4d00-a456-426614174000'
